import{_ as b,C as c,o as e,c as v,a0 as l,b as o,w as d,a as i,E as r,a1 as n,j as s}from"./chunks/framework.CrGeEOPE.js";const f=JSON.parse('{"title":"Float Parsing: Russ Cox Fast Unrounded Scaling","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://qbuem.com/qbuem-json/theory/russ-cox.html"}]]},"headers":[],"relativePath":"theory/russ-cox.md","filePath":"theory/russ-cox.md"}'),p={name:"theory/russ-cox.md"};function g(u,t,h,_,m,x){const a=c("Mermaid");return e(),v("div",null,[t[2]||(t[2]=l('<h1 id="float-parsing-russ-cox-fast-unrounded-scaling" tabindex="-1">Float Parsing: Russ Cox Fast Unrounded Scaling <a class="header-anchor" href="#float-parsing-russ-cox-fast-unrounded-scaling" aria-label="Permalink to &quot;Float Parsing: Russ Cox Fast Unrounded Scaling&quot;">​</a></h1><p>Standard library functions like <code>strtod</code> and <code>atof</code> are notoriously slow for high-throughput parsing. qbuem-json replaces them with a two-stage integer-only algorithm that produces bit-accurate IEEE-754 <code>double</code> results without touching the FPU rounding mode.</p><hr><h2 id="why-strtod-is-slow" tabindex="-1">Why <code>strtod</code> Is Slow <a class="header-anchor" href="#why-strtod-is-slow" aria-label="Permalink to &quot;Why `strtod` Is Slow&quot;">​</a></h2><div class="bd-diagram"><div class="bd-col"><div class="bd-box bd-box--red">strtod(str, &amp;end) called</div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-group" style="width:100%;max-width:500px;"><div class="bd-group__title">Hidden costs inside strtod</div><div class="bd-group__body"><div class="bd-steps"><div class="bd-step"><div class="bd-step__num">1</div><div class="bd-step__body"><div class="bd-step__title">STMXCSR — save FPU rounding mode</div><div class="bd-step__desc">Serializing instruction: stalls the entire CPU pipeline</div></div></div><div class="bd-step"><div class="bd-step__num">2</div><div class="bd-step__body"><div class="bd-step__title">LDMXCSR — set IEEE round-to-nearest</div><div class="bd-step__desc">Another pipeline flush</div></div></div><div class="bd-step"><div class="bd-step__num">3</div><div class="bd-step__body"><div class="bd-step__title">Sequential digit accumulation</div><div class="bd-step__desc">result = result × 10.0 + digit (7–17 floating-point multiplies)</div></div></div><div class="bd-step"><div class="bd-step__num">4</div><div class="bd-step__body"><div class="bd-step__title">FPU rounding error accumulates</div><div class="bd-step__desc">Each step adds error — may require expensive correction loop</div></div></div><div class="bd-step"><div class="bd-step__num">5</div><div class="bd-step__body"><div class="bd-step__title">LDMXCSR — restore original rounding mode</div><div class="bd-step__desc">Third pipeline flush</div></div></div></div></div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--orange">double returned<br><small>(after ~80–200 ns)</small></div></div></div><p><code>STMXCSR</code> / <code>LDMXCSR</code> are <strong>serializing instructions</strong> — they prevent the CPU from executing any subsequent instruction until the FPU state is written back to memory. For a parser targeting 2.7 GB/s, even a single <code>strtod</code> call per number would destroy all SIMD gains.</p><hr><h2 id="ieee-754-double-layout" tabindex="-1">IEEE-754 Double Layout <a class="header-anchor" href="#ieee-754-double-layout" aria-label="Permalink to &quot;IEEE-754 Double Layout&quot;">​</a></h2><p>Before understanding the algorithm, it helps to see the target bit pattern:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-group" style="max-width:560px;width:100%;"><div class="bd-group__title">IEEE-754 double — 64 bits total</div><div class="bd-group__body"><div class="bd-bits" style="max-width:520px;width:100%;"><div class="bd-bit-seg" style="width:60px;flex-shrink:0;background:rgba(244,67,54,0.15);border:1px solid rgba(244,67,54,0.4);border-radius:4px 0 0 4px;"><span class="bd-bit-seg__range">bit 63</span><span class="bd-bit-seg__val" style="color:#f44336;">Sign</span><span class="bd-bit-seg__name">1 bit</span></div><div class="bd-bit-seg" style="width:130px;flex-shrink:0;background:rgba(255,152,0,0.12);border:1px solid rgba(255,152,0,0.4);"><span class="bd-bit-seg__range">bits 62–52</span><span class="bd-bit-seg__val" style="color:#ff9800;">Exponent</span><span class="bd-bit-seg__name">11 bits · bias 1023</span></div><div class="bd-bit-seg" style="flex:1;background:color-mix(in srgb,var(--vp-c-brand-1) 10%,transparent);border:1px solid color-mix(in srgb,var(--vp-c-brand-1) 40%,transparent);border-radius:0 4px 4px 0;"><span class="bd-bit-seg__range">bits 51–0</span><span class="bd-bit-seg__val">Mantissa</span><span class="bd-bit-seg__name">52 bits · implicit 1.0</span></div></div><div style="font-size:0.78rem;color:var(--vp-c-text-2);font-family:var(--vp-font-family-mono);margin-top:0.5rem;">value = (−1)^sign × 1.mantissa × 2^(exponent − 1023)</div></div></div></div></div><p>The goal of float parsing: compute these three fields from a decimal string using <strong>only integer arithmetic</strong>.</p><hr><h2 id="the-two-stage-decision-pipeline" tabindex="-1">The Two-Stage Decision Pipeline <a class="header-anchor" href="#the-two-stage-decision-pipeline" aria-label="Permalink to &quot;The Two-Stage Decision Pipeline&quot;">​</a></h2><p>qbuem-json never calls <code>strtod</code>. Every decimal string goes through two integer-only stages:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-box bd-box--brand" style="max-width:340px;">Decimal string: &quot;3.141592653589793&quot;</div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">SIMD-assisted extraction</div></div><div class="bd-row" style="gap:1rem;"><div class="bd-box bd-box--teal" style="min-width:140px;">Integer mantissa m<br><small>3141592653589793</small></div><div class="bd-box bd-box--teal" style="min-width:140px;">Decimal exponent e<br><small>−15 (15 digits after point)</small></div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-group" style="width:100%;max-width:520px;"><div class="bd-group__title">Stage 1 — Eisel-Lemire (64-bit fast path)</div><div class="bd-group__body"><div class="bd-steps"><div class="bd-step"><div class="bd-step__num">1</div><div class="bd-step__body"><div class="bd-step__title">Look up 64-bit approximation of 10^e</div></div></div><div class="bd-step"><div class="bd-step__num">2</div><div class="bd-step__body"><div class="bd-step__title">64 × 64 → 128-bit multiply (MULQ, 3 cycles)</div></div></div><div class="bd-step"><div class="bd-step__num">3</div><div class="bd-step__body"><div class="bd-step__title">Inspect top 53 bits: unambiguous?</div></div></div></div></div></div><div class="bd-row" style="gap:1rem;align-items:flex-start;"><div class="bd-col" style="flex:1;"><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">unambiguous (~99%)</div></div><div class="bd-box bd-box--green" style="font-size:0.78rem;">Exact IEEE-754 result<br><small>no FPU · no rounding mode</small></div></div><div class="bd-col" style="flex:1;"><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">half-way case (~1%)</div></div><div class="bd-group"><div class="bd-group__title">Stage 2 — Russ Cox 128-bit Exact</div><div class="bd-group__body"><div class="bd-box bd-box--orange" style="font-size:0.75rem;">64 × 128 → 192-bit multiply</div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--green" style="font-size:0.75rem;">Exact IEEE-754 result</div></div></div></div></div></div></div><p>There is <strong>no third stage</strong>. qbuem-json never falls back to <code>strtod</code>.</p><hr><h2 id="mantissa-extraction-simd-assisted" tabindex="-1">Mantissa Extraction (SIMD-Assisted) <a class="header-anchor" href="#mantissa-extraction-simd-assisted" aria-label="Permalink to &quot;Mantissa Extraction (SIMD-Assisted)&quot;">​</a></h2><p>For a decimal string like <code>&quot;1.23456789&quot;</code>:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-group" style="width:100%;max-width:520px;"><div class="bd-group__title">SIMD digit scan — &quot;1.23456789&quot;</div><div class="bd-group__body"><div class="bd-steps"><div class="bd-step"><div class="bd-step__num">1</div><div class="bd-step__body"><div class="bd-step__title">Load up to 16 chars into NEON/SSE register</div></div></div><div class="bd-step"><div class="bd-step__num">2</div><div class="bd-step__body"><div class="bd-step__title">VPCMPEQB: detect non-digit chars (. e E + -)</div></div></div><div class="bd-step"><div class="bd-step__num">3</div><div class="bd-step__body"><div class="bd-step__title">VPSUBB: subtract &#39;0&#39; from each digit byte</div></div></div><div class="bd-step"><div class="bd-step__num">4</div><div class="bd-step__body"><div class="bd-step__title">VPMULLW + VPHADDD: fused multiply-accumulate</div><div class="bd-step__desc">d0×10^8 + d1×10^7 + … + d8×10^0</div></div></div></div></div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-row" style="gap:1rem;"><div class="bd-box bd-box--teal" style="min-width:140px;">m = 123456789<br><small>(integer mantissa)</small></div><div class="bd-box bd-box--teal" style="min-width:140px;">e = −8<br><small>(8 decimal places)</small></div></div></div></div><p>Up to 18 significant digits can be packed into a 64-bit integer without overflow (<code>2^63 ≈ 9.2 × 10^18</code>).</p><hr><h2 id="stage-1-eisel-lemire-64-bit-approximation" tabindex="-1">Stage 1: Eisel-Lemire 64-bit Approximation <a class="header-anchor" href="#stage-1-eisel-lemire-64-bit-approximation" aria-label="Permalink to &quot;Stage 1: Eisel-Lemire 64-bit Approximation&quot;">​</a></h2><p>The precomputed table stores a 64-bit approximation of <code>10^e</code>. The product <code>m × approx(10^e)</code> yields a 128-bit integer:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-group" style="width:100%;max-width:540px;"><div class="bd-group__title">64 × 64 → 128-bit product (MULQ instruction)</div><div class="bd-group__body bd-group__body--row"><div class="bd-box bd-box--brand" style="flex:1;">High 64 bits<br><small>integer part of m × 10^e<br>(contains the mantissa)</small></div><div class="bd-box" style="flex:1;">Low 64 bits<br><small>fractional precision indicator<br>(tells us if result is exact)</small></div></div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-group" style="width:100%;max-width:540px;"><div class="bd-group__title">Ambiguity test</div><div class="bd-group__body"><div class="bd-steps"><div class="bd-step"><div class="bd-step__num">1</div><div class="bd-step__body"><div class="bd-step__title">Find bit position P</div><div class="bd-step__desc">Leading-zero count of high 64 bits</div></div></div><div class="bd-step"><div class="bd-step__num">2</div><div class="bd-step__body"><div class="bd-step__title">Extract bits [P, P−52]</div><div class="bd-step__desc">Candidate 52-bit mantissa</div></div></div><div class="bd-step"><div class="bd-step__num">3</div><div class="bd-step__body"><div class="bd-step__title">Are remaining low bits exactly 0x800…0?</div><div class="bd-step__desc">Checks if result is exactly halfway between two representable values</div></div></div></div></div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-row" style="gap:1rem;"><div class="bd-box bd-box--green" style="flex:1;">Not halfway<br><small>→ emit IEEE-754 directly (~99%)</small></div><div class="bd-box bd-box--orange" style="flex:1;">Exactly halfway<br><small>→ fall through to Stage 2 (~1%)</small></div></div></div></div><p>&quot;Unambiguous&quot; means the product&#39;s mantissa bits are the same regardless of whether we round the approximation up or down.</p><hr><h2 id="stage-2-russ-cox-128-bit-exact-path" tabindex="-1">Stage 2: Russ Cox 128-bit Exact Path <a class="header-anchor" href="#stage-2-russ-cox-128-bit-exact-path" aria-label="Permalink to &quot;Stage 2: Russ Cox 128-bit Exact Path&quot;">​</a></h2><p>For the ~1% of inputs where Eisel-Lemire is ambiguous, qbuem-json uses a precomputed <strong>128-bit exact multiplier</strong> for each power of 10:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-group" style="width:100%;max-width:540px;"><div class="bd-group__title">Precomputed table: pow10_exact[e + 342]</div><div class="bd-group__body"><div class="bd-box" style="font-size:0.75rem;font-family:monospace;">e = −342: 0xFA8FD5A0081C0288 9F0B8A2E0E0FF381</div><div class="bd-box" style="font-size:0.75rem;font-family:monospace;">e = 0: 0x8000000000000000 0000000000000000</div><div class="bd-box" style="font-size:0.75rem;font-family:monospace;">e = 308: 0xE8D4A51000000000 0000000000000000</div><div class="bd-badge bd-badge--brand" style="margin-top:0.3rem;">651 entries · 10.2 KB · fits in L1 cache</div></div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">64-bit m × 128-bit C_e → 192-bit product</div></div><div class="bd-group" style="width:100%;max-width:540px;"><div class="bd-group__title">192-bit product layout</div><div class="bd-group__body bd-group__body--row"><div class="bd-box bd-box--brand" style="flex:1;">bits 191–128<br><small>high</small></div><div class="bd-box bd-box--teal" style="flex:1;">bits 127–64<br><small>middle</small></div><div class="bd-box" style="flex:1;">bits 63–0<br><small>low</small></div></div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-group" style="width:100%;max-width:540px;"><div class="bd-group__title">Mantissa extraction</div><div class="bd-group__body"><div class="bd-steps"><div class="bd-step"><div class="bd-step__num">1</div><div class="bd-step__body"><div class="bd-step__title">Find P = position of highest set bit</div></div></div><div class="bd-step"><div class="bd-step__num">2</div><div class="bd-step__body"><div class="bd-step__title">Extract bits [P, P−52]: the 52-bit mantissa</div></div></div><div class="bd-step"><div class="bd-step__num">3</div><div class="bd-step__body"><div class="bd-step__title">Round bit + Sticky bits</div><div class="bd-step__desc">Round bit = bit P−53 · Sticky = OR of all bits below P−53</div></div></div></div></div></div></div></div><h3 id="the-192-bit-multiplication" tabindex="-1">The 192-bit Multiplication <a class="header-anchor" href="#the-192-bit-multiplication" aria-label="Permalink to &quot;The 192-bit Multiplication&quot;">​</a></h3><p>On x86-64, the full 64×128→192-bit multiply decomposes into two <code>MULQ</code> instructions and one <code>ADCQ</code> (add with carry):</p>',32)),(e(),o(n,null,{default:d(()=>[r(a,{id:"mermaid-72",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20subgraph%20DECOMPOSE%5B%22C_e%20split%20into%20two%2064-bit%20halves%22%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20CH%5B%22C_hi%20%3D%20upper%2064%20bits%20of%20C_e%22%5D%0A%20%20%20%20%20%20%20%20CL%5B%22C_lo%20%3D%20lower%2064%20bits%20of%20C_e%22%5D%0A%20%20%20%20%20%20%20%20CH%20---%20CL%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20MULS%5B%22Two%20multiplications%20merged%20with%20carry%22%5D%0A%20%20%20%20%20%20%20%20direction%20TB%0A%20%20%20%20%20%20%20%20M1%5B%22MULQ%3A%20m%20%C3%97%20C_hi%20%E2%86%92%20128-bit%20product%20p_hh%22%5D%0A%20%20%20%20%20%20%20%20M2%5B%22MULQ%3A%20m%20%C3%97%20C_lo%20%E2%86%92%20128-bit%20product%20p_lh%22%5D%0A%20%20%20%20%20%20%20%20ADD%5B%22ADCQ%3A%20p_hh.lo%20%2B%20p_lh.hi%20(with%20carry)%3Cbr%2F%3E%E2%86%92%20192-bit%20total%20product%22%5D%0A%20%20%20%20%20%20%20%20M1%20--%3E%20ADD%0A%20%20%20%20%20%20%20%20M2%20--%3E%20ADD%0A%20%20%20%20end%0A%0A%20%20%20%20DECOMPOSE%20--%3E%20MULS%0A"})]),fallback:d(()=>[...t[0]||(t[0]=[i(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=s("p",null,[i("The entire Stage 2 path executes in "),s("strong",null,"~20 cycles"),i(" — 6× faster than "),s("code",null,"strtod"),i(".")],-1)),t[4]||(t[4]=s("hr",null,null,-1)),t[5]||(t[5]=s("h2",{id:"ieee-round-to-nearest-even",tabindex:"-1"},[i("IEEE Round-to-Nearest-Even "),s("a",{class:"header-anchor",href:"#ieee-round-to-nearest-even","aria-label":'Permalink to "IEEE Round-to-Nearest-Even"'},"​")],-1)),t[6]||(t[6]=s("p",null,"The round bit and sticky bits determine rounding:",-1)),(e(),o(n,null,{default:d(()=>[r(a,{id:"mermaid-83",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20RB%5B%22Round%20bit%20%3D%20bit%20P%E2%88%9253%20of%20the%20192-bit%20product%3Cbr%2F%3E(1%20%3D%20round%20up%20candidate%2C%200%20%3D%20truncate)%22%5D%0A%20%20%20%20SB%5B%22Sticky%20bit%20%3D%20OR%20of%20all%20bits%20below%20P%E2%88%9253%3Cbr%2F%3E(1%20%3D%20not%20exactly%20halfway%2C%200%20%3D%20exact%20midpoint)%22%5D%0A%0A%20%20%20%20CASE1%5B%22round_bit%20%3D%200%3Cbr%2F%3E%E2%86%92%20Truncate%3A%20keep%20mantissa%20as-is%22%5D%0A%20%20%20%20CASE2%5B%22round_bit%20%3D%201%20AND%20sticky%20%3D%201%3Cbr%2F%3E%E2%86%92%20Round%20up%3A%20add%201%20to%20mantissa%22%5D%0A%20%20%20%20CASE3%5B%22round_bit%20%3D%201%20AND%20sticky%20%3D%200%3Cbr%2F%3E(exactly%20halfway)%3Cbr%2F%3E%E2%86%92%20Round%20to%20nearest%20EVEN%3Cbr%2F%3Eadd%201%20only%20if%20mantissa%20LSB%20%3D%201%22%5D%0A%0A%20%20%20%20RB%20--%3E%20CASE1%20%26%20CASE2%20%26%20CASE3%0A%20%20%20%20SB%20--%3E%20CASE3%0A"})]),fallback:d(()=>[...t[1]||(t[1]=[i(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=l('<p>This logic executes entirely in integer registers — <strong>no FPU, no rounding mode, no serializing instructions</strong>.</p><hr><h2 id="powers-of-ten-table" tabindex="-1">Powers-of-Ten Table <a class="header-anchor" href="#powers-of-ten-table" aria-label="Permalink to &quot;Powers-of-Ten Table&quot;">​</a></h2><p>The table covers <code>10^−342</code> through <code>10^308</code> — the full range of IEEE-754 <code>double</code>:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Range</th><th style="text-align:right;">Entries</th><th style="text-align:right;">Size</th></tr></thead><tbody><tr><td style="text-align:left;">e = −342 to −1</td><td style="text-align:right;">342</td><td style="text-align:right;">5.3 KB</td></tr><tr><td style="text-align:left;">e = 0</td><td style="text-align:right;">1</td><td style="text-align:right;">16 B</td></tr><tr><td style="text-align:left;">e = +1 to +308</td><td style="text-align:right;">308</td><td style="text-align:right;">4.8 KB</td></tr><tr><td style="text-align:left;"><strong>Total</strong></td><td style="text-align:right;"><strong>651</strong></td><td style="text-align:right;"><strong>10.2 KB</strong></td></tr></tbody></table><p>10.2 KB fits comfortably in a 32 KB L1 data cache. For number-heavy workloads (financial data, sensor streams), the table stays <strong>permanently hot</strong> across the entire parse session.</p><hr><h2 id="performance-comparison" tabindex="-1">Performance Comparison <a class="header-anchor" href="#performance-comparison" aria-label="Permalink to &quot;Performance Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:right;"><code>strtod</code> / <code>atof</code></th><th style="text-align:right;">Eisel-Lemire (Stage 1)</th><th style="text-align:right;">Russ Cox (Stage 2)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Instructions</strong></td><td style="text-align:right;">~200</td><td style="text-align:right;">~25</td><td style="text-align:right;">~60</td></tr><tr><td style="text-align:left;"><strong>Pipeline flushes</strong></td><td style="text-align:right;">2 (<code>STMXCSR</code>/<code>LDMXCSR</code>)</td><td style="text-align:right;"><strong>0</strong></td><td style="text-align:right;"><strong>0</strong></td></tr><tr><td style="text-align:left;"><strong>FPU operations</strong></td><td style="text-align:right;">7–17</td><td style="text-align:right;"><strong>0</strong></td><td style="text-align:right;"><strong>0</strong></td></tr><tr><td style="text-align:left;"><strong>Table lookup</strong></td><td style="text-align:right;">none</td><td style="text-align:right;">8 bytes</td><td style="text-align:right;">16 bytes</td></tr><tr><td style="text-align:left;"><strong>Throughput</strong></td><td style="text-align:right;">~120 ns</td><td style="text-align:right;"><strong>~8 ns</strong></td><td style="text-align:right;"><strong>~20 ns</strong></td></tr><tr><td style="text-align:left;"><strong>Frequency</strong></td><td style="text-align:right;">—</td><td style="text-align:right;">~99% of inputs</td><td style="text-align:right;">~1% of inputs</td></tr></tbody></table><p><strong>Weighted average: ~8.1 ns per float</strong> vs ~120 ns for <code>strtod</code> — a <strong>~15× speedup</strong> for number-heavy documents.</p><hr><h2 id="correctness-guarantee" tabindex="-1">Correctness Guarantee <a class="header-anchor" href="#correctness-guarantee" aria-label="Permalink to &quot;Correctness Guarantee&quot;">​</a></h2><p>qbuem-json produces the <strong>correctly rounded IEEE-754 result</strong> for all possible finite decimal inputs:</p><ul><li>All decimal strings with ≤ 15 significant digits: provably exact via Eisel-Lemire</li><li>All remaining inputs: provably exact via the 128-bit Russ Cox path</li><li>No input ever produces a result that differs from <code>strtod</code>&#39;s correctly-rounded output</li></ul><blockquote><p>The algorithm is bit-for-bit identical to <code>strtod</code> on all inputs — it is simply <strong>15× faster</strong> by avoiding FPU rounding-mode manipulation and sequential decimal multiplication.</p></blockquote>',15))])}const w=b(p,[["render",g]]);export{f as __pageData,w as default};
